"""Оркестратор эксперимента.`run(...)` — одиночный запуск (совместимость со всеми прежними вызовами).`run_series(...)` — серия испытаний с несколькими фильтрами и режимом seed."""from __future__ import annotationsimport secretsfrom datetime import datetime, timezonefrom typing import Anyfrom ..metrics import compute_allfrom .aggregation import aggregate_resultsfrom .registry import Registryfrom .types import AggregatedMetrics, ExperimentResult, ExperimentSeriesclass ExperimentPipeline:    def __init__(self, registry: Registry) -> None:        if not isinstance(registry, Registry):            raise TypeError("registry must be a Registry instance")        self._registry = registry    @property    def registry(self) -> Registry:        return self._registry    # ------------------- одиночный прогон (старое API, НЕ меняется) -------    def run(self,            signal_name: str, signal_params: dict[str, Any] | None = None,            noise_name: str = "", noise_params: dict[str, Any] | None = None,            filter_name: str = "", filter_params: dict[str, Any] | None = None,            ) -> ExperimentResult:        if not signal_name or not noise_name or not filter_name:            raise ValueError(                "pipeline.run: signal_name, noise_name and filter_name are required"            )        signal_params = dict(signal_params or {})        noise_params = dict(noise_params or {})        filter_params = dict(filter_params or {})        signal_impl = self._registry.get_signal(signal_name)        noise_impl = self._registry.get_noise(noise_name)        filter_impl = self._registry.get_filter(filter_name)        clean = signal_impl.generate(**signal_params)        noisy = noise_impl.apply(clean, **noise_params)        restored = filter_impl.apply(noisy, **filter_params)        if not (clean.x.shape == noisy.x.shape == restored.x.shape):            raise RuntimeError(                f"pipeline.run: length mismatch "                f"(clean={clean.x.size}, noisy={noisy.x.size}, "                f"restored={restored.x.size})"            )        metrics = compute_all(clean, noisy, restored)        timestamp = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")        used_seed = int(noisy.params.get("seed", noise_params.get("seed", 0)))        return ExperimentResult(            clean=clean, noisy=noisy, restored=restored,            metrics=metrics,            signal_name=signal_name, noise_name=noise_name, filter_name=filter_name,            timestamp=timestamp,            trial_index=0,            seed=used_seed,        )    # ------------------- серия прогонов (новое API) -----------------------    def run_series(self,                   signal_name: str, signal_params: dict[str, Any],                   noise_name: str, noise_params: dict[str, Any],                   filter_specs: list[tuple[str, dict[str, Any]]],                   n_trials: int = 1,                   seed_mode: str = "manual",                   ) -> ExperimentSeries:        """Запустить серию испытаний.        :param filter_specs: список кортежей (filter_name, filter_params).            Порядок в списке = порядок отображения в таблицах/графиках.        :param n_trials: ≥ 1.        :param seed_mode:            "manual" — seed берётся из noise_params['seed']; для i-го испытания                       используется (seed + i). Это обеспечивает разные                       реализации шума и воспроизводимость.            "auto"   — для каждого испытания генерируется новый случайный seed                       через secrets.randbits(31) и сохраняется в ExperimentResult.        """        if n_trials < 1:            raise ValueError("n_trials must be >= 1")        if not filter_specs:            raise ValueError("filter_specs must be non-empty")        if seed_mode not in ("manual", "auto"):            raise ValueError(f"unknown seed_mode: {seed_mode!r}")        noise_params = dict(noise_params or {})        base_seed = int(noise_params.get("seed", 0)) if seed_mode == "manual" else 0        filter_names: list[str] = [fname for fname, _ in filter_specs]        results: dict[str, list[ExperimentResult]] = {f: [] for f in filter_names}        timestamp = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")        # Для каждого испытания i:        #   * выбираем seed (manual → base+i, auto → случайный);        #   * один раз генерируем clean+noisy, чтобы все фильтры сравнивались        #     на ОДНОМ и том же зашумлённом сигнале;        #   * применяем каждый фильтр к этому noisy.        signal_impl = self._registry.get_signal(signal_name)        noise_impl = self._registry.get_noise(noise_name)        for i in range(n_trials):            trial_seed = (base_seed + i) if seed_mode == "manual" \                else int(secrets.randbits(31))            trial_noise_params = dict(noise_params)            trial_noise_params["seed"] = trial_seed            clean = signal_impl.generate(**dict(signal_params))            noisy = noise_impl.apply(clean, **trial_noise_params)            for fname, fparams in filter_specs:                filter_impl = self._registry.get_filter(fname)                restored = filter_impl.apply(noisy, **dict(fparams))                if not (clean.x.shape == noisy.x.shape == restored.x.shape):                    raise RuntimeError(                        f"pipeline.run_series: length mismatch for filter {fname!r}"                    )                metrics = compute_all(clean, noisy, restored)                res = ExperimentResult(                    clean=clean, noisy=noisy, restored=restored,                    metrics=metrics,                    signal_name=signal_name,                    noise_name=noise_name,                    filter_name=fname,                    timestamp=timestamp,                    trial_index=i,                    seed=trial_seed,                )                results[fname].append(res)        aggregates: dict[str, AggregatedMetrics] = {            fname: aggregate_results(fname, results[fname])            for fname in filter_names        }        return ExperimentSeries(            signal_name=signal_name,            noise_name=noise_name,            filter_names=filter_names,            n_trials=n_trials,            seed_mode=seed_mode,            base_seed=base_seed,            timestamp=timestamp,            results=results,            aggregates=aggregates,        )